25→  return (
26→    <div className="space-y-6">
27→      <PageHeader title="QR Codes" description="Générez des QR codes pour vos programmes." />
28→      <QrGenerator
29→        programs={programs || []}
30→        merchantId={user!.id}
31→        appUrl={process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000'}
32→      />
33→
34→      {/* Existing QR codes */}
35→      {qrCodes && qrCodes.length > 0 && (
36→        <div>
37→          <h2 className="text-[15px] font-semibold text-[var(--text-primary)] mb-4">QR codes existants</h2>
