43→                    {qr.loyalty_programs?.name || 'Programme'}
44→                  </p>
45→                  <Badge variant={qr.is_active ? 'success' : 'default'}>
46→                    {qr.is_active ? 'Actif' : 'Inactif'}
47→                  </Badge>
48→                </div>
49→                <p className="text-[11px] text-[var(--text-tertiary)] break-all">{qr.qr_url}</p>
50→                <p className="text-[11px] text-[var(--text-tertiary)] mt-1">
