 1→export const dynamic = 'force-dynamic';
 2→
 3→import PageHeader from '@/components/layout/PageHeader';
 4→import Card from '@/components/ui/Card';
 5→import Badge from '@/components/ui/Badge';
 6→import RewardForm from '@/components/merchant/RewardForm';
 7→import { createServerSupabase } from '@/lib/supabase/server';
 8→
 9→export default async function RewardsPage() {
10→  const supabase = await createServerSupabase();
11→  const { data: { user } } = await supabase.auth.getUser();
12→
13→  const { data: programs } = await supabase
14→    .from('loyalty_programs')
15→    .select('*')
16→    .eq('merchant_id', user!.id)
17→    .eq('is_active', true);
18→
19→  // Fetch rewards for all merchant programs
20→  const programIds = programs?.map(p => p.id) || [];
21→  const { data: rewards } = programIds.length > 0
22→    ? await supabase
23→        .from('rewards')
24→        .select('*, loyalty_programs(name)')
25→        .in('program_id', programIds)
26→        .order('created_at', { ascending: false })
27→    : { data: [] };
28→
29→  const discountLabel = (type: string, value: number) => {
30→    if (type === 'freebie') return 'Gratuit';
31→    if (type === 'percentage') return `${value}%`;
32→    return `${value}€`;
33→  };
34→
35→  return (
36→    <div className="space-y-6">
37→      <PageHeader title="Récompenses" description="Gérez les récompenses de vos programmes." />
38→
39→      <RewardForm programs={programs || []} />
40→
41→      {rewards && rewards.length > 0 && (
42→        <div>
43→          <h2 className="text-[15px] font-semibold text-[var(--text-primary)] mb-4">Récompenses existantes</h2>
44→          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
45→            {rewards.map((r: any, i: number) => (
46→              <Card key={r.id} className={`stagger-enter stagger-${Math.min(i + 1, 6)}`}>
47→                <div className="flex items-center justify-between mb-2">
48→                  <h3 className="text-[15px] font-semibold text-[var(--text-primary)]">{r.name}</h3>
49→                  <Badge variant={r.is_active ? 'success' : 'default'}>
50→                    {r.is_active ? 'Active' : 'Inactive'}
51→                  </Badge>
52→                </div>
53→                <p className="text-[13px] text-[var(--text-tertiary)]">
54→                  {(r as any).loyalty_programs?.name || 'Programme'} — {discountLabel(r.discount_type, r.discount_value)}
55→                </p>
56→              </Card>
57→            ))}
58→          </div>
59→        </div>
60→      )}
61→
62→      {(!rewards || rewards.length === 0) && programs && programs.length > 0 && (
63→        <Card className="text-center py-8">
64→          <p className="text-[var(--text-tertiary)] text-[13px]">Aucune récompense. Créez-en une ci-dessus !</p>
65→        </Card>
66→      )}
67→    </div>
68→  );
69→}
