 8→export default async function ClientsPage() {
 9→  const supabase = await createServerSupabase();
10→  const { data: { user } } = await supabase.auth.getUser();
11→
12→  // Get merchant's programs
13→  const { data: programs } = await supabase
14→    .from('loyalty_programs')
15→    .select('id')
16→    .eq('merchant_id', user!.id);
17→
18→  const programIds = programs?.map(p => p.id) || [];
19→
20→  // Fetch customer cards for these programs
21→  const { data: cards } = programIds.length > 0
22→    ? await supabase
23→        .from('customer_cards')
