29→  const tierVariant = (tier: string) => {
30→    if (tier === 'vip') return 'accent';
31→    if (tier === 'gold') return 'warning';
32→    if (tier === 'silver') return 'blue';
33→    return 'default';
34→  };
35→
36→  return (
37→    <div className="space-y-6">
38→      <PageHeader title="Clients" description="Consultez et gérez vos clients fidélité." />
