46→            <span>Solde</span>
47→            <span>Tier</span>
48→            <span>Inscription</span>
49→          </div>
50→
51→          <div className="divide-y divide-[var(--border-subtle)]">
52→            {cards.map((card: any) => (
53→              <div key={card.id} className="grid grid-cols-1 md:grid-cols-5 gap-2 md:gap-4 px-5 py-3 items-center">
54→                <div>
55→                  <p className="text-[13px] font-medium text-[var(--text-primary)]">
56→                    {card.customers?.full_name || 'Client'}
57→                  </p>
58→                  <p className="text-[11px] text-[var(--text-tertiary)]">{card.customers?.email}</p>
59→                </div>
60→                <p className="text-[13px] text-[var(--text-secondary)]">{card.loyalty_programs?.name}</p>
61→                <p className="text-[13px] text-[var(--text-primary)] font-medium">
62→                  {card.balance} / {card.loyalty_programs?.target} {card.loyalty_programs?.type === 'stamp' ? 'tampons' : 'pts'}
63→                </p>
