 77→          <div className="flex gap-2">
 78→            {([
 79→              { value: 'freebie', label: 'Gratuit' },
 80→              { value: 'percentage', label: '%' },
 81→              { value: 'fixed', label: '€' },
 82→            ] as const).map(t => (
 83→              <button key={t.value} type="button" onClick={() => update('discount_type', t.value)}
 84→                className={`flex-1 px-3 py-2 rounded-lg text-sm border transition-all ${
