16→  const update = (key: string, value: string | number) => setForm(prev => ({ ...prev, [key]: value }));
17→
18→  const handleSubmit = async (e: React.FormEvent) => {
19→    e.preventDefault();
20→    setLoading(true);
21→    const supabase = createClient();
22→
23→    const { error } = await supabase.from('loyalty_programs').insert({
24→      merchant_id: merchantId,
25→      name: form.name,
26→      type: form.type,
27→      stamp_goal: form.type === 'stamp' ? form.stampGoal : null,
28→      points_per_euro: form.type === 'points' ? form.pointsPerEuro : null,
29→      welcome_bonus_stamps: form.type === 'stamp' ? form.welcomeBonusStamps : 0,
30→      welcome_bonus_points: form.type === 'points' ? form.welcomeBonusPoints : 0,
31→    });
32→
33→    if (error) { toast.error(error.message); setLoading(false); return; }
34→    toast.success('Programme créé !');
35→    router.push('/merchant/programs');
36→    router.refresh();
37→  };
38→
39→  return (
40→    <Card padding="lg" className="max-w-lg">
41→      <form onSubmit={handleSubmit} className="space-y-4">
42→        <Input label="Nom du programme" value={form.name} onChange={e => update('name', e.target.value)} required placeholder="ex: Carte Café" />
43→
44→        <div className="space-y-1.5">
45→          <label className="text-[13px] font-medium text-[var(--text-secondary)]">Type</label>
46→          <div className="flex gap-3">
47→            {(['stamp', 'points'] as const).map(t => (
48→              <button key={t} type="button" onClick={() => update('type', t)}
49→                className={`flex-1 px-4 py-2 rounded-lg text-sm border transition-all ${
50→                  form.type === t
51→                    ? 'border-[var(--accent)] bg-[var(--accent-subtle)] text-[var(--accent-text)] font-medium'
52→                    : 'border-[var(--border-default)] text-[var(--text-secondary)] hover:border-[var(--border-strong)]'
53→                }`}
54→              >
55→                {t === 'stamp' ? 'Tampons' : 'Points'}
56→              </button>
57→            ))}
58→          </div>
59→        </div>
60→
61→        {form.type === 'stamp' ? (
62→          <Input label="Tampons requis" type="number" min={1}
63→            value={String(form.stampGoal)} onChange={e => update('stampGoal', parseInt(e.target.value) || 1)} />
64→        ) : (
65→          <Input label="Points par euro" type="number" min={1}
66→            value={String(form.pointsPerEuro)} onChange={e => update('pointsPerEuro', parseInt(e.target.value) || 1)} />
67→        )}
68→
69→        <Input label={form.type === 'stamp' ? 'Bonus de bienvenue (tampons)' : 'Bonus de bienvenue (points)'} type="number" min={0}
70→          value={String(form.type === 'stamp' ? form.welcomeBonusStamps : form.welcomeBonusPoints)}
71→          onChange={e => update(form.type === 'stamp' ? 'welcomeBonusStamps' : 'welcomeBonusPoints', parseInt(e.target.value) || 0)} />
72→
73→        <div className="flex gap-3 pt-2">
74→          <Button type="submit" loading={loading}>Créer le programme</Button>
75→          <Button variant="ghost" onClick={() => router.back()}>Annuler</Button>
76→        </div>
77→      </form>
78→    </Card>
79→  );
